INSERT INTO `produit` (`id`, `nom`, `description`, `prix`, `img`) VALUES
(1, 'Tomate', 'Tomate fraîche issue de l’agriculture biologique, cultivée sans pesticides ni engrais de synthèse, dans le respect des sols et de la biodiversité. Sa chair juteuse et parfumée offre une saveur douce et équilibrée, idéale aussi bien crue (salades, tartines, carpaccios) que cuite (sauces, rôties au four, poêlées). Produite selon un cahier des charges strict, elle provient de graines sélectionnées, d’un sol enrichi en matière organique et d’une gestion naturelle des maladies et ravageurs. Récoltée à maturité, elle présente une peau fine, une couleur uniformément rouge et un parfum marqué, garantissant un produit sain, de saison et respectueux de l’environnement.', 1.5, 'img/tomate.jpg'),
